export interface PointsConfig {
  scopeId: string;
  bpMonetaryValue: number;
  bpCurrency: string;
  bpTimeValue: number;
  bpTimeUnit: string;
  spMonetaryValue: number;
  spCurrency: string;
  spTimeValue: number;
  spTimeUnit: string;
}

export const DEFAULT_POINTS_CONFIG: Omit<PointsConfig, "scopeId"> = {
  bpMonetaryValue: 0.225,
  bpCurrency: "Mill. NOK",
  bpTimeValue: 1,
  bpTimeUnit: "hours",
  spMonetaryValue: 0.6,
  spCurrency: "Mill. NOK",
  spTimeValue: 1,
  spTimeUnit: "hours",
};
